import AppKit

/// The anchor glyph shown beside the app name in the menu header.
///
/// Embedded as a base64-encoded PNG rather than shipped as a bundle resource: the app is packaged
/// as a bare executable (see `Scripts/package_app.sh`), so a self-contained asset avoids adding a
/// resource bundle. The source art is small and retina-safe, since it renders only a handful of
/// points tall in the menu header.
enum AnchorAsset {
    static let image: NSImage? = {
        guard let data = Data(base64Encoded: pngBase64),
              let image = NSImage(data: data) else { return nil }
        return image
    }()

    private static let pngBase64 = """
    
    """
}
